package com.helios.platform.service;import com.helios.platform.model.*;import org.springframework.stereotype.Service;import java.time.Instant;import java.util.*;@Service public class DeviceService{private final Map<String,Device> devices=new LinkedHashMap<>();public DeviceService(){devices.put("ev",new Device("ev","Helios X EV","Connected Vehicle","ONLINE",94,28.4,"v4.2.1","BATTERY_HEALTH_UPDATED"));devices.put("watch",new Device("watch","Helios Pulse Watch","Wearable","ONLINE",82,31.0,"v2.8.0","HEART_RATE_SYNCED"));devices.put("camera",new Device("camera","Helios Vision Camera","Security Camera","ONLINE",76,34.2,"v3.1.4","MOTION_EVENT_STREAMED"));devices.put("thermo",new Device("thermo","Helios Nest Thermostat","Smart Home","ONLINE",88,22.0,"v5.0.2","TEMP_COMMAND_ACCEPTED"));devices.put("energy",new Device("energy","Helios Energy Hub","Energy Device","ONLINE",91,30.5,"v1.9.7","LOAD_BALANCED"));}public Collection<Device> all(){return devices.values();}public Optional<Device> get(String id){return Optional.ofNullable(devices.get(id));}public TelemetryEvent telemetry(String id){return new TelemetryEvent(id,"TELEMETRY_RECEIVED",Math.round((20+Math.random()*80)*10)/10.0,"metric",Instant.now());}}
